// V20: 参数化查询重构 — 消除 SQL 注入风险
const req = $input.item.json;
const params = req.query || {};
return { json: {
  type: params.type || '',
  status: params.status || '',
  date_from: params.date_from || '',
  date_to: params.date_to || ''
} };

let rows = [];
try { rows = $('Query Documents').all(); } catch(e) { rows = []; }
const documents = rows.filter(function(r) { return r.json && r.json.id; }).map(function(r) { return r.json; });
return { json: { success: true, documents: documents } };

const req = $input.item.json;
let docId = '';
if (req.query && req.query.id) {
  docId = req.query.id;
} else {
  const url = req.headers && req.headers['x-original-url'] ? req.headers['x-original-url'] : (req.url || '');
  const parts = url.split('/');
  const lastPart = parts[parts.length - 1];
  docId = lastPart ? lastPart.split('?')[0] : '';
}
const docType = (req.query && req.query.type) ? req.query.type : '';
if (!docId || docId === 'document' || docId === 'undefined') {
  return { json: { _error: true, success: false, message: '请提供单据编号' } };
}
return { json: { _error: false, docId: docId, docType: docType } };

let headerRows = [];
try { headerRows = $('Query Doc Header').all(); } catch(e) {
  return { json: { success: false, message: '单据查询失败: ' + e.message } };
}
let txRows = [];
try { txRows = $('Query Doc Transactions').all(); } catch(e) { txRows = []; }

if (!headerRows || headerRows.length === 0 || !headerRows[0].json.id) {
  return { json: { success: false, message: '未找到该单据' } };
}

const first = headerRows[0].json;
const document = {
  id: first.id,
  doc_type: first.doc_type,
  doc_number: first.doc_number,
  sap_doc_num: first.sap_doc_num || '',
  status: first.status,
  wms_status: first.wms_status || first.status,
  warehouse_code: first.warehouse_code || '',
  business_partner: first.business_partner || '',
  bp_name: first.bp_name || '',
  doc_date: first.doc_date,
  created_by: first.created_by || '',
  remarks: first.remarks || '',
  created_at: first.created_at,
  exported_at: first.exported_at
};

const lines = [];
const seenLines = {};
for (const r of headerRows) {
  if (r.json.line_id && !seenLines[r.json.line_id]) {
    seenLines[r.json.line_id] = true;
    lines.push({
      id: r.json.line_id,
      line_num: r.json.line_num,
      item_code: r.json.item_code || '',
      item_name: r.json.item_name || '',
      uom: r.json.uom || '',
      planned_qty: parseFloat(r.json.planned_qty) || 0,
      actual_qty: parseFloat(r.json.actual_qty) || 0,
      warehouse_code: r.json.line_whs || '',
      bin_location: r.json.bin_location || '',
      from_warehouse: r.json.from_warehouse || '',
      from_bin: r.json.from_bin || '',
      to_warehouse: r.json.to_warehouse || '',
      to_bin: r.json.to_bin || '',
      status: r.json.line_status || '',
      wms_status: r.json.line_wms_status || r.json.line_status || '',
      updated_at: r.json.created_at
    });
  }
}

// 去重: n8n多行输入会导致Query Doc Transactions重复执行, 按id去重
const seenTx = {};
const transactions = [];
for (const r of txRows) {
  if (r.json.id && !seenTx[r.json.id]) {
    seenTx[r.json.id] = true;
    transactions.push({
      id: r.json.id,
      action: r.json.action,
      item_code: r.json.item_code,
      quantity: parseFloat(r.json.quantity),
      warehouse_code: r.json.warehouse_code || '',
      bin_location: r.json.bin_location || '',
      from_bin: r.json.from_bin || '',
      to_bin: r.json.bin_location || '',
      item_name: r.json.item_name || '',
      performed_by: r.json.performed_by || '',
      remarks: r.json.remarks || '',
      transaction_time: r.json.transaction_time
    });
  }
}

return { json: { success: true, document: document, lines: lines, transactions: transactions } };
